use aiken/collection/list
use cardano/address
use cardano/assets
use cardano/transaction.{OutputReference, Transaction}
use aiken/crypto.{Blake2b_224, Hash, VerificationKey}

type VerificationKeyHash = Hash<Blake2b_224, VerificationKey>

type OwnerDatum {
  owner: VerificationKeyHash,
  locked_lovelace: Int,
}

validator owner_withdrawal {
  fn spend(
    datum: Option<OwnerDatum>,
    _redeemer: Data,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(d) = datum
    let owner_signed = list.has(self.extra_signatories, d.owner)
    let owner_address = address.from_verification_key(d.owner)
    let sufficient_output =
      list.any(
        self.outputs,
        fn(o) {
          o.address == owner_address && assets.lovelace_of(o.value) >= d.locked_lovelace
        },
      )
    owner_signed && sufficient_output
  }
}

