  client: VerificationKeyHash,
  milestone_amount: Int,
  total_remaining: Int,
}

validator milestone_payment {
  fn spend(datum: Option<MilestoneDatum>, _redeemer: Data, _own_ref: OutputReference, self: Transaction) -> Bool {
    expect Some(d) = datum
    let client_signed = list.has(self.extra_signatories, d.client)
    let contractor_addr = address.from_verification_key(d.contractor)
    let contractor_paid = list.any(self.outputs, fn(o) {
      o.address == contractor_addr && assets.lovelace_of(o.value) >= d.milestone_amount
    })
    // El resto debe quedar bloqueado en algún output del script
    let leftover = d.total_remaining - d.milestone_amount
    let has_leftover = leftover <= 0 || list.any(self.outputs, fn(o) {
      assets.lovelace_of(o.value) >= leftover
    })
    client_signed && contractor_paid && has_leftover
  }
}

