  nft_policy: assets.PolicyId,
  nft_name: assets.AssetName,
}

validator dutch_auction {
  fn spend(datum: Option<DutchAuctionDatum>, _redeemer: Data, _own_ref: OutputReference, self: Transaction) -> Bool {
    expect Some(d) = datum
    let elapsed = d.current_time - d.start_time
    let discount = elapsed * d.discount_per_slot
    let current_price =
      if d.start_price - discount < d.floor_price {
        d.floor_price
      } else {
        d.start_price - discount
      }
    let seller_addr = address.from_verification_key(d.seller)
    let seller_paid = list.any(self.outputs, fn(o) {
      o.address == seller_addr && assets.lovelace_of(o.value) >= current_price
    })
    let nft_moved = list.any(self.outputs, fn(o) {
      assets.has_nft(o.value, d.nft_policy, d.nft_name)
    })
    seller_paid && nft_moved
  }
}

