validator threshold_mint(signers: List<VerificationKeyHash>, threshold: Int) {
  fn mint(_redeemer: Data, _policy_id: PolicyId, self: Transaction) -> Bool {
    let valid_sigs =
      list.count(signers, fn(k) { list.has(self.extra_signatories, k) })
    valid_sigs >= threshold
  }

  else(_) {
    fail
  }
}

use aiken/interval
use cardano/transaction.{Transaction}

validator time_window_mint(start_time: Int, end_time: Int) {
  fn mint(_redeemer: Data, _policy_id: PolicyId, self: Transaction) -> Bool {
    let valid_window = interval.between(start_time, end_time)
    interval.includes(valid_window, self.validity_range)
  }

  else(_) {
    fail
  }
}

