validator authorized_burn(admin: VerificationKeyHash) {
  fn mint(_redeemer: Data, policy_id: PolicyId, self: Transaction) -> Bool {
    let is_admin_signed = list.has(self.extra_signatories, admin)
    let all_burning =
      self.mint
        |> assets.tokens(policy_id)
        |> dict.to_pairs()
        |> list.all(fn(Pair(_name, qty)) { qty < 0 })
    is_admin_signed && all_burning
  }

  else(_) {
    fail
  }
}

