validator capped_nft_mint(admin: VerificationKeyHash, per_tx_cap: Int) {
  fn mint(_redeemer: Data, policy_id: PolicyId, self: Transaction) -> Bool {
    let is_admin_signed = list.has(self.extra_signatories, admin)
    let total_minted =
      self.mint
        |> assets.tokens(policy_id)
        |> dict.to_pairs()
        |> list.foldl(0, fn(Pair(_name, qty), acc) { acc + qty })
    is_admin_signed && total_minted > 0 && total_minted <= per_tx_cap
  }

  else(_) {
    fail
  }
}

use aiken/collection/dict
