validator acunacion_unica(utxo_ref: OutputReference) {
  fn mint(_redeemer: Data, policy_id: PolicyId, self: Transaction) -> Bool {
    let Transaction { inputs, mint, .. } = self
    let utxo_consumida =
      list.any(inputs, fn(input) { input.output_reference == utxo_ref })
    expect [Pair(_nombre_activo, cantidad)] =
      mint
        |> assets.tokens(policy_id)
        |> dict.to_pairs()
    utxo_consumida && cantidad == 1
  }

  else(_) {
    fail
  }
}

