use aiken/builtin
use aiken/cbor
use aiken/collection/dict
use aiken/collection/list
use cardano/assets
use cardano/transaction.{OutputReference, Transaction}

validator nft_unico_con_nombre(utxo_ref: OutputReference) {
  fn mint(_redeemer: Data, policy_id: PolicyId, self: Transaction) -> Bool {
    let Transaction { inputs, mint, .. } = self
    let utxo_consumida =
      list.any(inputs, fn(i) { i.output_reference == utxo_ref })
    expect Some(primera_entrada) = list.at(inputs, 0)
    let nombre_esperado =
      primera_entrada.output_reference
        |> cbor.serialise
        |> builtin.blake2b_256
    expect [Pair(nombre_activo, cantidad)] =
      mint
        |> assets.tokens(policy_id)
        |> dict.to_pairs()
    utxo_consumida && nombre_activo == nombre_esperado && cantidad == 1
  }

  else(_) {
    fail
  }
}

