  min_lovelace: Int,
}

validator min_reward_withdrawal {
  fn withdraw(
    redeemer: MinWithdrawRedeemer,
    account: Credential,
    self: Transaction,
  ) -> Bool {
    let is_signed = list.has(self.extra_signatories, redeemer.owner)
    let withdrawn_amount =
      when list.find(self.withdrawals, fn(pair) { pair.1st == account }) is {
        Some(pair) -> pair.2nd
        None -> 0
      }
    is_signed && withdrawn_amount >= redeemer.min_lovelace
  }
}

