use aiken/collection/list
use cardano/assets
use cardano/transaction.{OutputReference, Transaction, find_input}

pub type OracleDatum {
  price: Int
}

pub type SpendDatum {
  config_ref: OutputReference
  beneficiary: ByteArray
}

validator oracle_price_check {
  fn spend(
    datum: Option<SpendDatum>,
    _redeemer: Data,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(d) = datum
    expect Some(oracle_input) =
      find_input(self.reference_inputs, d.config_ref)
    expect InlineDatum(raw) = oracle_input.output.datum
    expect oracle_datum: OracleDatum = raw
    let paid =
      list.any(
        self.outputs,
        fn(o) { assets.lovelace_of(o.value) >= oracle_datum.price },
      )
    paid
  }
}

